double v_min = 0.5;
double denom = fabs(v_vehicle);

if (denom < v_min) {
    denom = v_min;
}

double slip_local = (v_wheel - v_vehicle) / denom;

if (slip_local > 1.0) {
    slip_local = 1.0;
}
if (slip_local < -1.0) {
    slip_local = -1.0;
}

slip = slip_local;

if (slip_local > 0.001) {
    slip_sign = 1.0;
} else if (slip_local < -0.001) {
    slip_sign = -1.0;
} else {
    slip_sign = 0.0;
}
/*End code section*/

